script:
async function generateSitemap() {
  const supabase = window.supabaseClient;

  const { data } = await supabase
    .from("articles")
    .select("slug, updated_at")
    .eq("status", "published");

  const urls = data.map(article => `

      https://www.sentrum.com.tw/article.html?slug=${article.slug}
      ${article.updated_at}

  `).join("");

  const xml = `

    ${urls}
  `;

  document.body.innerText = xml;
}

generateSitemap();
